/**
 * IWAC Visualizations — Publication issue dashboard (orchestrator)
 *
 * Per-issue view for the `publications` subset (Islamic periodical
 * issues, bibo:Issue — resource template 21 on islam.zmo.de). Loads
 * `asset/data/publication-dashboards/{o_id}.json` (one file per issue,
 * generated by scripts/generate_publication_dashboards.py) and renders:
 *
 *   1. A stat-card row — words / pages / issue number / language /
 *      country / date. Cards with missing values are elided.
 *   2. `wordCloud` — the most frequent words in this issue's text,
 *      from a precomputed frequency list (lemmas, OCR as fallback).
 *   3. `siblingSparkline` — the issue's periodical run (issues per
 *      year for the same periodical, zero-filled) with this issue's
 *      year dotted.
 *   4. `similarItems` — "Similar issues": semantic neighbours over
 *      embedding_tableOfContents (768-dim Gemini). This replaced an
 *      earlier chronological "other issues of this periodical" strip
 *      now that the table-of-contents embeddings cover the subset.
 *
 * Dependencies: dashboard-layout + word-cloud + sibling-sparkline +
 * similar-items renderers (declared via the partial's
 * $needs['renderers']), plus chartOptions + the echarts-wordcloud
 * extension ($needs['chartOptions'] + $needs['wordcloud']).
 */
(function () {
    'use strict';

    var ns = window.IWACVis;
    if (!ns || !ns.panels || !ns.dashboardLayout) {
        console.warn('IWACVis publication dashboard: missing dependencies — check script load order');
        return;
    }
    var P  = ns.panels;
    var DL = ns.dashboardLayout;

    /* ----------------------------------------------------------------- */
    /*  Layout — three declarative slots                                  */
    /* ----------------------------------------------------------------- */

    DL.register('publication', [
        { chart: 'wordCloud', wide: true,
          dataKey: 'wordcloud',
          title: 'Most frequent words in this issue',
          description: 'desc_publication_wordcloud' },
        { chart: 'siblingSparkline', wide: true,
          dataKey: 'sparkline',
          title: 'This issue in its periodical run',
          description: 'desc_publication_run' },
        { chart: 'similarItems', wide: true,
          dataKey: 'semantic_neighbors',
          title: 'Similar issues',
          description: 'desc_publication_similar',
          options: { max: 8 } }
    ]);

    /* ----------------------------------------------------------------- */
    /*  Stat cards                                                        */
    /* ----------------------------------------------------------------- */

    /**
     * P.buildSummaryCards always runs values through formatNumber,
     * which mangles strings — build the same card DOM here with
     * per-field formatting instead. Returns null when every metric is
     * missing so the caller can skip the row entirely.
     */
    function buildMetricCards(metrics) {
        var asDate = function (v) {
            // Publication dates can be ranges ("2009-05/2009-08") that
            // Date can't parse — P.formatDate passes those through
            // verbatim, which is exactly what we want.
            return P.formatDate(v);
        };
        var defs = [
            { key: 'words',    label: 'Words',    format: P.formatNumber },
            { key: 'pages',    label: 'Pages',    format: P.formatNumber },
            { key: 'issue',    label: 'Issue' },
            { key: 'language', label: 'Language' },
            { key: 'country',  label: 'Country' },
            { key: 'date',     label: 'Date',     format: asDate }
        ];
        var row = P.el('div', 'iwac-vis-overview-summary');
        var rendered = 0;
        defs.forEach(function (d) {
            var v = metrics ? metrics[d.key] : null;
            if (v == null || v === '') return;
            var card = P.el('div', 'iwac-vis-summary-card');
            card.appendChild(P.el('div', 'iwac-vis-summary-card__label', P.t(d.label)));
            card.appendChild(P.el('div', 'iwac-vis-summary-card__value',
                d.format ? d.format(v) : String(v)));
            row.appendChild(card);
            rendered++;
        });
        return rendered > 0 ? row : null;
    }

    /* ----------------------------------------------------------------- */
    /*  Bootstrap                                                         */
    /* ----------------------------------------------------------------- */

    function initDashboard(container) {
        var itemId = container.dataset.itemId;
        if (!itemId) return;
        var basePath = container.dataset.basePath || '';
        var url = basePath + '/files/iwac-visualizations/publication-dashboards/'
            + itemId + '.json';

        P.fetchJSON(url)
            .then(function (data) {
                var loading = container.querySelector('.iwac-vis-publication__loading');
                if (loading) loading.remove();

                var body = P.el('div', 'iwac-vis-publication__body');
                container.appendChild(body);

                var cards = buildMetricCards(data.metrics);
                if (cards) body.appendChild(cards);

                var run = data.run || null;
                var sparkline = run ? {
                    years:     run.years,
                    values:    run.values,
                    highlight: run.highlight,
                    caption:   (run.newspaper ? run.newspaper + ' — ' : '')
                        + P.t('publications_count', { count: P.formatNumber(run.total || 0) })
                } : null;

                DL.render(body, 'publication', {
                    wordcloud:          data.wordcloud || [],
                    sparkline:          sparkline,
                    semantic_neighbors: data.semantic_neighbors || []
                }, {
                    siteBase: container.dataset.siteBase || '',
                    basePath: basePath,
                    data:     data
                });
            })
            .catch(function (err) {
                console.error('IWACVis publication dashboard:', err);
                var loading = container.querySelector('.iwac-vis-publication__loading');
                if (loading) loading.remove();
                container.appendChild(P.buildFetchErrorState(err));
            });
    }

    function init() {
        var containers = document.querySelectorAll('.iwac-vis-publication');
        for (var i = 0; i < containers.length; i++) {
            initDashboard(containers[i]);
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
